#include<bits/stdc++.h>
using namespace std;
long long n,m;
map<string,bool> mp;
bool vis[5001];
string a[5001];
void dfs(string str,long long x)
{
    if(x==n+1)
    {
        if(str.length()>=3&&!mp[str])
        {
            cout<<str;
            exit(0);
        }
        return;
    }
    for(long long i=1;i<=n;i++)
    {
        
        if(vis[i])
        {
            continue;
        }
        
        for(long long j=1;str.length()+a[i].length()+j<=16;j++)
        {
            string str1=str;
            for(long long k=1;k<=j;k++)
            {
                str1+='_';
            }
            str1+=a[i];
            vis[i]=1;
            dfs(str1,x+1);
            vis[i]=0;
        }
        
    }
}
int main()
{
    
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=n;i++)
    {
        cin>>a[i];
    }
    for(long long i=1;i<=m;i++)
    {
        string x;
        cin>>x;
        mp[x]=1;
    }
    for(int i=1;i<=n;i++)
    {
        vis[i]=1;
        dfs(a[i],2);
        vis[i]=0;
    }
    printf("-1");
    return 0;
}
